CREATE TABLE IF NOT EXISTS "public"."stripe_customers" (
    "id" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "auth_id" "uuid" NOT NULL,
    "stripe_customer_id" "text" NOT NULL,
    "tenant_id" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT ("now"() AT TIME ZONE 'utc'::"text") NOT NULL,
    CONSTRAINT "stripe_customers_auth_id_tenant_id_key" UNIQUE ("auth_id", "tenant_id"),
    CONSTRAINT "stripe_customers_stripe_customer_id_tenant_id_key" UNIQUE ("stripe_customer_id", "tenant_id")
);

CREATE INDEX "idx_stripe_customers_auth_id" ON "public"."stripe_customers" USING "btree" ("auth_id");
CREATE INDEX "idx_stripe_customers_stripe_customer_id" ON "public"."stripe_customers" USING "btree" ("stripe_customer_id");
CREATE INDEX "idx_stripe_customers_tenant_id" ON "public"."stripe_customers" USING "btree" ("tenant_id");

ALTER TABLE ONLY "public"."stripe_customers"
    ADD CONSTRAINT "stripe_customers_auth_id_fkey" FOREIGN KEY ("auth_id") REFERENCES "auth"."users"("id") ON UPDATE CASCADE ON DELETE CASCADE;

ALTER TABLE "public"."stripe_customers" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "tenant_isolation" ON "public"."stripe_customers" USING (("tenant_id" = ((SELECT current_setting('request.headers'::"text", true))::"json" ->> 'x-tenant-id'::"text")));

CREATE TABLE IF NOT EXISTS "public"."stripe_badge_products" (
    "id" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "stripe_product_id" "text" NOT NULL UNIQUE,
    "badge_id" bigint NOT NULL,
    "tenant_id" "text" NOT NULL,
    CONSTRAINT "stripe_badge_products_badge_id_fkey"
      FOREIGN KEY ("badge_id") REFERENCES "public"."profile_badges"("id")
      ON UPDATE CASCADE ON DELETE CASCADE
);

CREATE INDEX "idx_stripe_badge_products_stripe_product_id" ON "public"."stripe_badge_products" USING "btree" ("stripe_product_id");
CREATE INDEX "idx_stripe_badge_products_badge_id" ON "public"."stripe_badge_products" USING "btree" ("badge_id");
CREATE INDEX "idx_stripe_badge_products_tenant_id" ON "public"."stripe_badge_products" USING "btree" ("tenant_id");

ALTER TABLE "public"."stripe_badge_products" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "tenant_isolation" ON "public"."stripe_badge_products" USING (("tenant_id" = ((SELECT current_setting('request.headers'::"text", true))::"json" ->> 'x-tenant-id'::"text")));

CREATE TABLE IF NOT EXISTS "public"."stripe_tier_config" (
    "id" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "badge_id" bigint NOT NULL,
    "description" "text" NOT NULL,
    "color" "text" NOT NULL,
    "tenant_id" "text" NOT NULL,
    CONSTRAINT "stripe_tier_config_badge_id_tenant_id_key" UNIQUE ("badge_id", "tenant_id"),
    CONSTRAINT "stripe_tier_config_badge_id_fkey"
      FOREIGN KEY ("badge_id") REFERENCES "public"."profile_badges"("id")
      ON UPDATE CASCADE ON DELETE CASCADE
);

CREATE INDEX "idx_stripe_tier_config_badge_id" ON "public"."stripe_tier_config" USING "btree" ("badge_id");
CREATE INDEX "idx_stripe_tier_config_tenant_id" ON "public"."stripe_tier_config" USING "btree" ("tenant_id");

ALTER TABLE "public"."stripe_tier_config" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "tenant_isolation" ON "public"."stripe_tier_config" USING (("tenant_id" = ((SELECT current_setting('request.headers'::"text", true))::"json" ->> 'x-tenant-id'::"text")));

CREATE OR REPLACE FUNCTION "public"."read_secret"("secret_name" "text")
RETURNS "text"
LANGUAGE "plpgsql" SECURITY DEFINER
SET search_path = ''
AS $$
DECLARE
  secret_value text;
BEGIN
  SELECT decrypted_secret INTO secret_value
  FROM vault.decrypted_secrets
  WHERE name = secret_name
  LIMIT 1;

  RETURN secret_value;
END;
$$;

REVOKE EXECUTE ON FUNCTION "public"."read_secret"("text") FROM "anon";
REVOKE EXECUTE ON FUNCTION "public"."read_secret"("text") FROM "authenticated";
